+    gap: 8px;
+    padding: 12px 20px;
+    border-top: 1px solid #e0e0e0;
+    flex-shrink: 0;
+    align-items: flex-end;
+}
+
+.message-textarea {
+    flex: 1;
+    resize: none;
+    border: 1px solid #ccc;
+    border-radius: 6px;
+    padding: 10px 12px;
+    font-size: 0.9rem;
+    font-family: inherit;
+    min-height: 40px;
+    max-height: 120px;
+    outline: none;
+    transition: border-color 0.15s;
+}
+
+.message-textarea:focus {
+    border-color: #1264a3;
+}
+
+.send-btn {
+    padding: 10px 20px;
+    background: #007a5a;
+    color: #fff;
+    border: none;
+    border-radius: 6px;
+    font-weight: 600;
+    font-size: 0.85rem;
+    cursor: pointer;
+    transition: background 0.15s;
+}
+
+.send-btn:hover:not(:disabled) {
+    background: #005e44;
+}
+
+.send-btn:disabled {
+    background: #ccc;
+    cursor: not-allowed;
+}
+
+/* No channel selected */
+.no-channel-selected {
+    flex: 1;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    color: #999;
+    font-size: 1.1rem;
+}
+
+/* Thread Panel */
+.thread-panel {
+    width: 25%;
+    min-width: 280px;
+    border-left: 1px solid #e0e0e0;
+    background: #fafafa;
+    display: flex;
+    flex-direction: column;
+}
+
+.thread-header {
+    display: flex;
+    align-items: center;
+    justify-content: space-between;
+    padding: 12px 16px;
+    border-bottom: 1px solid #e0e0e0;
+    flex-shrink: 0;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+.close-btn {
+    border: none;
+    background: transparent;
+    font-size: 1.2rem;
+    cursor: pointer;
+    padding: 4px 8px;
+    border-radius: 4px;
+    color: #666;
+}
+
+.close-btn:hover {
+    background: #e0e0e0;
+}
+
+.thread-root-message {
+    padding: 12px 16px;
+    border-bottom: 1px solid #e0e0e0;
+    background: #fff;
+    flex-shrink: 0;
+}
+
+.thread-root-message .message-author {
+    font-size: 0.85rem;
+}
+
+.thread-root-message .message-content {
+    margin-top: 4px;
+    font-size: 0.85rem;
+    color: #555;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 12px 16px;
+}
+
+.thread-panel .message-input-area {
+    padding: 12px 16px;
+}
+

