@page "/chat"
@using sv_1b1f96cc44cc416d906edc7ff605b81a.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* Left Sidebar - Channel List *@
    <aside class="chat-sidebar">
        <h3 class="sidebar-title">Channels</h3>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var channel in channels)
                {
                    <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-description">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* Main Message Area *@
    <main class="chat-main @(threadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <header class="chat-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </header>

            <div class="message-list" @onscroll="HandleScrollAsync" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages...</div>
                }
                @if (messages is not null)
                {
                    @foreach (var message in messages)
                    {
                        <div class="message-item" @onmouseenter="() => hoveredMessageId = message.Id"
                             @onmouseleave="() => hoveredMessageId = null">
                            <div class="message-header">
                                <span class="message-author">@message.Author</span>
                                <span class="message-time">@FormatRelativeTime(message.SentAt)</span>
                            </div>
                            <div class="message-content">@message.Content</div>

                            @* Reactions *@
                            @if (message.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in message.Reactions)
                                    {
                                        <span class="reaction-badge" @onclick="() => AddReactionAsync(message.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </span>
                                    }
                                </div>
                            }

                            @* Thread replies link *@
                            @if (GetThreadSummary(message.Id) is { } thread)
                            {
                                <a class="thread-link" @onclick="() => OpenThreadAsync(message.Id)">
                                    @thread.ReplyCount replies
                                </a>
                            }

                            @* Hover action buttons *@
                            @if (hoveredMessageId == message.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(message.Id)" title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-container">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(message.Id)" title="Add reaction">
                                            😀 React
                                        </button>
                                        @if (emojiPickerMessageId == message.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-option" @onclick="() => AddReactionAsync(message.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" @bind="newMessageContent" @bind:event="oninput"
                          placeholder="Type a message..." @onkeydown="HandleMainKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageContent)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* Right Panel - Thread View *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </header>
            <div class="thread-root-message">
                <span class="message-author">@threadRootMessage.Author</span>
                <p class="message-content">@threadRootMessage.Content</p>
            </div>
            <div class="thread-replies">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-item">
                            <div class="message-header">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <span class="reaction-badge">@reaction.Emoji @reaction.Users.Count</span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>
            <div class="message-input-area">
                <textarea class="message-textarea" @bind="threadReplyContent" @bind:event="oninput"
                          placeholder="Reply in thread..." @onkeydown="HandleThreadKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyContent)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel>? channels;
    private List<Message>? messages;
    private List<Message>? threadMessages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;

    private string newMessageContent = "";
    private string threadReplyContent = "";
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 30;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🤔", "👀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;
        await ChatService.MarkChannelReadAsync(channel.Id);
        await BuildThreadSummaries();
        emojiPickerMessageId = null;
    }

    private async Task BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replies = messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value));

        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return threadSummaries.TryGetValue(messageId, out var summary) ? summary : null;
    }

    private async Task HandleScrollAsync()
    {
        // Pagination triggered from UI; in a real app we'd use JS interop to detect scroll position.
        // Here we provide a method that can be wired to scroll-to-top detection.
    }

    internal async Task LoadOlderMessagesAsync()
    {
        if (activeChannel is null || isLoadingMore) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages = older.Concat(messages ?? []).ToList();
            messageSkip += older.Count;
            await BuildThreadSummaries();
        }
        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannel is null) return;
        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageContent.Trim(), null);
        messages ??= new();
        messages.Add(sent);
        messageSkip++;
        newMessageContent = "";
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages?.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
        threadReplyContent = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyContent) || threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyContent.Trim(), threadRootMessage.Id);
        threadMessages ??= new();
        threadMessages.Add(reply);
        threadReplyContent = "";

        // Update thread summary
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with { ReplyCount = existing.ReplyCount + 1, LastReplyAt = reply.SentAt };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to reflect new reaction
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

